// Categorize incoming email replies
const subject = ($input.item.json.subject || '').toLowerCase();
const body = ($input.item.json.text || $input.item.json.snippet || '').toLowerCase();
const from = $input.item.json.from?.text || $input.item.json.from || '';
const date = $input.item.json.date || new Date().toISOString();

// Keywords that signal interest
const positiveSignals = ['interested', 'love to', 'send me', 'tell me more', 'sounds great', 'let\'s chat', 'schedule', 'call', 'demo', 'link', 'app store', 'download', 'try it', 'check it out', 'yes', 'absolutely', 'definitely', 'would love', 'happy to', 'sure'];

// Keywords that signal not interested
const negativeSignals = ['unsubscribe', 'not interested', 'no thanks', 'remove me', 'stop', 'don\'t contact', 'opt out', 'pass on this', 'not a fit', 'not for us', 'no thank you'];

// Keywords that signal a question
const questionSignals = ['how does', 'what is', 'can you', 'do you', 'pricing', 'cost', 'features', 'how many', 'tell me about', 'more info', 'details', 'explain', '?'];

let category = 'unknown';
let confidence = 'low';
let suggestedAction = '';

// Check negative first (highest priority)
for (const signal of negativeSignals) {
  if (body.includes(signal) || subject.includes(signal)) {
    category = 'not_interested';
    confidence = 'high';
    suggestedAction = 'Remove from sequence. Do not follow up.';
    break;
  }
}

// Check positive
if (category === 'unknown') {
  for (const signal of positiveSignals) {
    if (body.includes(signal) || subject.includes(signal)) {
      category = 'interested';
      confidence = 'medium';
      suggestedAction = 'Reply with App Store link and offer a call. HIGH PRIORITY.';
      break;
    }
  }
}

// Check questions
if (category === 'unknown') {
  for (const signal of questionSignals) {
    if (body.includes(signal) || subject.includes(signal)) {
      category = 'question';
      confidence = 'medium';
      suggestedAction = 'Reply answering their question + include App Store link.';
      break;
    }
  }
}

// Default
if (category === 'unknown') {
  suggestedAction = 'Review manually — could not auto-categorize.';
}

// Determine which outreach list this might be from
let outreachType = 'unknown';
const subjectAndBody = subject + ' ' + body;
if (subjectAndBody.includes('press') || subjectAndBody.includes('coverage') || subjectAndBody.includes('story') || subjectAndBody.includes('editorial') || subjectAndBody.includes('publication')) {
  outreachType = 'press';
} else if (subjectAndBody.includes('collab') || subjectAndBody.includes('creator') || subjectAndBody.includes('content') || subjectAndBody.includes('feature') || subjectAndBody.includes('audience')) {
  outreachType = 'influencer';
} else if (subjectAndBody.includes('bar') || subjectAndBody.includes('staff') || subjectAndBody.includes('training') || subjectAndBody.includes('menu') || subjectAndBody.includes('bartend')) {
  outreachType = 'bar_partnership';
}

return [{
  json: {
    from: from,
    subject: $input.item.json.subject,
    snippet: ($input.item.json.snippet || '').substring(0, 300),
    body_preview: body.substring(0, 500),
    date: date,
    category: category,
    confidence: confidence,
    outreach_type: outreachType,
    suggested_action: suggestedAction,
    message_id: $input.item.json.id || ''
  }
}];
